import React, { useEffect, useState } from "react";
import Navbar from "./Navbar";
import "./Home.css";

function Home() {
  const [username, setUsername] = useState("");
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const [allProducts, setAllProducts] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [carouselIndex, setCarouselIndex] = useState(0);
  const [filteredProducts, setFilteredProducts] = useState([]);
  const [email, setEmail] = useState("");
  const [newsletter, setNewsletter] = useState("");

  // Infer category from product data if category field is missing
  const inferCategory = (product) => {
    const name = product.name?.toLowerCase() || "";
    if (name.includes("phone") || name.includes("laptop") || name.includes("tablet") || name.includes("camera")) {
      return "electronics";
    }
    if (name.includes("shirt") || name.includes("jeans") || name.includes("jacket") || name.includes("dress")) {
      return "clothing";
    }
    if (name.includes("sofa") || name.includes("lamp") || name.includes("table") || name.includes("home") || name.includes("garden")) {
      return "home";
    }
    if (name.includes("soccer") || name.includes("football") || name.includes("ball") || name.includes("bike") || name.includes("sport")) {
      return "sports";
    }
    return "other";
  };

  // Categories list
  const categories = [
    { id: "all", name: "All Products", icon: "🛍" },
    { id: "electronics", name: "Electronics", icon: "📱" },
    { id: "clothing", name: "Clothing", icon: "👕" },
    { id: "home", name: "Home & Garden", icon: "🏠" },
    { id: "sports", name: "Sports", icon: "⚽" },
    { id: "other", name: "Other", icon: "✨" }
  ];

  // Testimonials
  const testimonials = [
    { name: "John Doe", text: "Amazing products and fast delivery!", rating: 5 },
    { name: "Sarah Smith", text: "Great customer service and quality items.", rating: 5 },
    { name: "Mike Johnson", text: "Best prices I've found online!", rating: 4 }
  ];

  // Initialize
  useEffect(() => {
    const storedUser = localStorage.getItem("username");
    if (storedUser) {
      setUsername(storedUser);
    } else {
      window.location.href = "/";
    }

    // Fetch products
    fetch("/api/products")
      .then((res) => res.json())
      .then((data) => {
        const enriched = data.map((product) => ({
          ...product,
          category: product.category || inferCategory(product)
        }));

        setAllProducts(enriched);
        setFeaturedProducts(enriched.slice(0, 5)); // First 5 as featured
        setFilteredProducts(enriched);
      })
      .catch((err) => console.error("Error fetching products:", err));
  }, []);

  // Auto-rotate carousel
  useEffect(() => {
    if (featuredProducts.length === 0) return;
    const timer = setInterval(() => {
      setCarouselIndex((prev) => (prev + 1) % featuredProducts.length);
    }, 4000);
    return () => clearInterval(timer);
  }, [featuredProducts]);

  // Handle search and filter
  useEffect(() => {
    let filtered = allProducts;

    // Filter by category
    if (selectedCategory !== "all") {
      filtered = filtered.filter((p) =>
        p.category?.toLowerCase().includes(selectedCategory.toLowerCase())
      );
    }

    // Filter by search query
    if (searchQuery) {
      filtered = filtered.filter((p) =>
        p.name.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    setFilteredProducts(filtered);
  }, [searchQuery, selectedCategory, allProducts]);

  // Handle newsletter signup
  const handleNewsletterSignup = () => {
    if (email) {
      setNewsletter("✅ Thank you for subscribing!");
      setEmail("");
      setTimeout(() => setNewsletter(""), 3000);
    }
  };

  // Navigate to products page
  const goToProducts = () => {
    window.location.href = "/products";
  };

  return (
    <div className="home-container">
      <Navbar />

      {/* HERO SECTION */}
      <section className="hero-section">
        <div className="hero-content">
          <h1 className="hero-title">Welcome to the E-Commerce App 🛒</h1>
          <p className="hero-subtitle">Hello, <strong>{username}</strong> 👋</p>
          <p className="hero-tagline">Shop smart. Live better.</p>
          <button className="cta-button" onClick={goToProducts}>
            🛍 Shop Now
          </button>
        </div>
      </section>

      {/* PROMOTIONAL BANNER */}
      <section className="promo-banner">
        <div className="promo-content">
          <h2>🎉 Special Offer! Get 20% OFF on First Purchase</h2>
          <p>Use code: WELCOME20</p>
        </div>
      </section>

      {/* FEATURED PRODUCTS CAROUSEL */}
      {featuredProducts.length > 0 && (
        <section className="featured-section">
          <h2 className="section-title">⭐ Featured Products</h2>
          <div className="carousel-container">
            <button
              className="carousel-btn prev"
              onClick={() =>
                setCarouselIndex(
                  (prev) =>
                    (prev - 1 + featuredProducts.length) % featuredProducts.length
                )
              }
            >
              ❮
            </button>

            <div className="carousel-display">
              {featuredProducts[carouselIndex] && (
                <div className="carousel-card">
                  <img
                    src={
                      featuredProducts[carouselIndex].image ||
                      "https://via.placeholder.com/300"
                    }
                    alt={featuredProducts[carouselIndex].name}
                  />
                  <h3>{featuredProducts[carouselIndex].name}</h3>
                  <p className="price">₹{featuredProducts[carouselIndex].price}</p>
                  <button className="add-btn">Add to Cart ➕</button>
                </div>
              )}
            </div>

            <button
              className="carousel-btn next"
              onClick={() =>
                setCarouselIndex((prev) => (prev + 1) % featuredProducts.length)
              }
            >
              ❯
            </button>
          </div>

          {/* Carousel indicators */}
          <div className="carousel-indicators">
            {featuredProducts.map((_, idx) => (
              <div
                key={idx}
                className={`indicator ${idx === carouselIndex ? "active" : ""}`}
                onClick={() => setCarouselIndex(idx)}
              />
            ))}
          </div>
        </section>
      )}

      {/* CATEGORIES SECTION */}
      <section className="categories-section">
        <h2 className="section-title">📂 Browse Categories</h2>
        <div className="categories-grid">
          {categories.map((cat) => (
            <button
              key={cat.id}
              className={`category-card ${
                selectedCategory === cat.id ? "active" : ""
              }`}
              onClick={() => setSelectedCategory(cat.id)}
            >
              <span className="category-icon">{cat.icon}</span>
              <span className="category-name">{cat.name}</span>
            </button>
          ))}
        </div>
      </section>

      {/* SEARCH & FILTER SECTION */}
      <section className="search-section">
        <div className="search-container">
          <input
            type="text"
            placeholder="🔍 Search products..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="search-input"
          />
        </div>
      </section>

      {/* PRODUCTS GRID */}
      {filteredProducts.length > 0 && (
        <section className="products-showcase">
          <h2 className="section-title">
            {selectedCategory === "all" ? "All Products" : "Category Products"}
          </h2>
          <div className="products-grid">
            {filteredProducts.slice(0, 8).map((product) => (
              <div key={product.id} className="product-showcase-card">
                <div className="product-image-container">
                  <img
                    src={product.image || "https://via.placeholder.com/150"}
                    alt={product.name}
                  />
                  <div className="product-overlay">
                    <button className="quick-view-btn">Quick View</button>
                  </div>
                </div>
                <h3>{product.name}</h3>
                <p className="product-price">₹{product.price}</p>
                <button className="product-add-btn">Add to Cart ➕</button>
              </div>
            ))}
          </div>
        </section>
      )}

      {filteredProducts.length === 0 && (
        <section className="no-products">
          <p>❌ No products found. Try a different search or category.</p>
        </section>
      )}

      {/* TESTIMONIALS SECTION */}
      <section className="testimonials-section">
        <h2 className="section-title">💬 What Customers Say</h2>
        <div className="testimonials-grid">
          {testimonials.map((testimonial, idx) => (
            <div key={idx} className="testimonial-card">
              <div className="stars">{"⭐".repeat(testimonial.rating)}</div>
              <p className="testimonial-text">"{testimonial.text}"</p>
              <p className="testimonial-author">— {testimonial.name}</p>
            </div>
          ))}
        </div>
      </section>

      {/* NEWSLETTER SIGNUP */}
      <section className="newsletter-section">
        <div className="newsletter-content">
          <h2>📧 Subscribe to Our Newsletter</h2>
          <p>Get updates on new products and special offers!</p>
          <div className="newsletter-form">
            <input
              type="email"
              placeholder="Enter your email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="newsletter-input"
            />
            <button
              className="newsletter-btn"
              onClick={handleNewsletterSignup}
            >
              Subscribe
            </button>
          </div>
          {newsletter && <p className="newsletter-success">{newsletter}</p>}
        </div>
      </section>

      {/* CTA SECTION */}
      <section className="cta-section">
        <h2>Ready to Start Shopping?</h2>
        <button className="cta-button-large" onClick={goToProducts}>
          Browse All Products →
        </button>
      </section>
    </div>
  );
}

export default Home;
